    // اضافه کردن متد هوشمند به DownloadLinkGenerator.cs
    public string GetAttachmentLink(string fileName)
    {
        var extension = Path.GetExtension(fileName)?.ToLower();

        var link = extension switch
        {
            ".pdf" => PdfLink(fileName),
            ".png" or ".jpg" or ".jpeg" => FormImageLink(fileName), // یا ImageLink
            _ => Generate(options.Value.EmailFilesUrl, fileName) // یک پوشه پیش‌فرض برای بقیه فایل‌ها
        };

        #region agent log
        try
        {
            var payload = System.Text.Json.JsonSerializer.Serialize(new
            {
                sessionId = "0d2c16",
                runId = "pre-fix",
                hypothesisId = "H1",
                location = "DownloadLinkGenerator.cs:GetAttachmentLink",
                message = "attachment link generated",
                data = new
                {
                    fileName,
                    extension,
                    chosenFolder = extension is ".pdf" ? options.Value.PdfFilesUrl
                        : extension is ".png" or ".jpg" or ".jpeg" ? options.Value.FormImagesUrl
                        : options.Value.EmailFilesUrl,
                    emailFilesPath = options.Value.EmailFiles,
                    formImagesPath = options.Value.FormImages,
                    generatedLink = link,
                    fileExistsInEmailFiles = File.Exists(Path.Combine(options.Value.EmailFiles, Path.GetFileName(fileName))),
                    fileExistsInFormImages = File.Exists(Path.Combine(options.Value.FormImages, Path.GetFileName(fileName)))
                },
                timestamp = DateTimeOffset.UtcNow.ToUnixTimeMilliseconds()
            });
            File.AppendAllText(@"d:\Elay_Backend-master\debug-0d2c16.log", payload + Environment.NewLine);
        }
        catch { }
        #endregion

        return link;
    }
}

